class Solution {
public:
int connectedComponents(vector<vector<int>>& graph) {
	int count = 0;
	vector<bool> visited(graph.size(), false);
	for (int i = 0; i < graph.size(); i++) {
		if (!visited[i]) {
			count++;
			DFS(graph, visited, i);
		}
	}
	return count;
}
void DFS(vector<vector<int>>& graph, vector<bool>& visited, int vertex) {
	visited[vertex] = true;
	for (int v : graph[vertex]) {
		if (!visited[v]) {
			DFS(graph, visited, v);
		}
	}
}
};

